
'use server';

import { doc, setDoc, getDoc, serverTimestamp, increment } from 'firebase/firestore';
import { getFirestoreDb } from './firebase';

export interface UserProfile {
  uid: string;
  email: string | null;
  isSubscribed: boolean;
  credits: number;
  createdAt: any; // Use 'any' to avoid serialization issues with Timestamps
  lastLogin?: any;
}

// Function to create or update a user profile in Firestore
export async function updateUserProfile(uid: string, data: Partial<Omit<UserProfile, 'isSubscribed' | 'credits' | 'createdAt' | 'lastLogin'>>) {
  const db = await getFirestoreDb();
  const userRef = doc(db, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    // If the user profile already exists, just update it without changing createdAt.
    await setDoc(userRef, {
      ...data,
      lastLogin: serverTimestamp(),
    }, { merge: true });
  } else {
    // If it's a new user, create the profile with the initial data and createdAt.
    await setDoc(userRef, {
      ...data,
      isSubscribed: false,
      credits: 1, // Give 1 free credit on signup
      createdAt: serverTimestamp(),
      lastLogin: serverTimestamp(),
    }, { merge: true });
  }
}

// Function to check subscription status and get user profile
export async function checkUserSubscription(uid: string): Promise<UserProfile | null> {
  const db = await getFirestoreDb();
  const userRef = doc(db, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    const data = docSnap.data();
    // Convert server timestamps to serializable format (ISO string)
    // This is safer for passing from server components/actions to client components
    return {
        ...data,
        createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toISOString() : new Date().toISOString(),
        lastLogin: data.lastLogin?.toDate ? data.lastLogin.toDate().toISOString() : new Date().toISOString(),
    } as UserProfile;
  } else {
    // Create the profile if it doesn't exist. This can happen in some edge cases.
    // However, it's better to ensure profile is created on signup/login.
    // For now, return null as the user profile should have been created on login.
    return null;
  }
}

// Function to activate a user's subscription and add credits
export async function activateUserSubscription(uid: string) {
    const db = await getFirestoreDb();
    const userRef = doc(db, 'users', uid);
    const docSnap = await getDoc(userRef);

    if (!docSnap.exists()) {
        throw new Error("User profile does not exist. Cannot activate subscription.");
    }
    
    await setDoc(userRef, {
        isSubscribed: true,
        credits: increment(15), // Add 15 credits upon subscription
    }, { merge: true });
}

export async function decrementUserCredits(uid: string) {
    const db = await getFirestoreDb();
    const userRef = doc(db, 'users', uid);
    const docSnap = await getDoc(userRef);

    if (!docSnap.exists()) {
        throw new Error("User profile does not exist.");
    }

    const currentCredits = docSnap.data().credits || 0;
    if (currentCredits > 0) {
        await setDoc(userRef, {
            credits: increment(-1),
        }, { merge: true });
    } else {
        // This case should ideally be handled on the client, but as a safeguard:
        throw new Error("User has no credits to decrement.");
    }
}
