
'use server';

import { generateKissVideo, type GenerateKissVideoInput } from '@/ai/flows/generate-kiss-video';
import { fuseImages, type FuseImagesInput } from '@/ai/flows/fuse-images-flow';

// This action no longer requires the API key to be passed from the client.
export async function createKissVideoAction(
  input: GenerateKissVideoInput
): Promise<{ videoDataUri?: string; sourceImageDataUri?: string; error?: string }> {
  // The API key is now handled on the backend exclusively.
  if (!process.env.GEMINI_API_KEY) {
    return { error: 'The Gemini API key is not configured on the server. Please contact support.' };
  }
  
  try {
    const result = await generateKissVideo(input);
    if (!result.videoDataUri || !result.sourceImageDataUri) {
      return { error: 'The AI failed to return a video or source image. Please try again.' };
    }
    return { videoDataUri: result.videoDataUri, sourceImageDataUri: result.sourceImageDataUri };
  } catch (e) {
    console.error('Video generation error:', e);
    const message = e instanceof Error ? e.message : 'An unknown error occurred.';
    
    // Provide more user-friendly error messages.
    if (message.includes('quota')) {
        return { error: 'We are experiencing high demand and have run out of capacity. Please try again later.' };
    }
    if (message.includes('Invalid argument') || message.includes('could not process the image') || message.includes('Status: 400')) {
        return { error: 'The AI could not process the image(s). Please try with different, higher-quality photos (clear, well-lit faces).' };
    }
    if (message.includes('API key not valid') || message.includes('API key is invalid') || message.includes('GEMINI_API_KEY')) {
        return { error: 'The API key configured on the server is invalid. Please contact support.' };
    }
    if (message.includes('User has no credits')) {
        return { error: 'You do not have enough credits to generate a video. Please subscribe or renew to get more.' };
    }
    
    return { error: `An unexpected error occurred during video generation. Please try again or contact support if the problem persists.` };
  }
}

export async function fuseImagesAction(input: FuseImagesInput): Promise<{ imageDataUri?: string; error?: string; }> {
    try {
        const result = await fuseImages(input);
        return { imageDataUri: result.imageDataUri };
    } catch (e) {
        return { error: e instanceof Error ? e.message : 'Unknown error during image fusion.' };
    }
}
