
import { initializeApp, getApps, getApp, type FirebaseApp } from 'firebase/app';
import { getAuth, type Auth } from 'firebase/auth';
import { getFirestore as getClientFirestore, type Firestore } from 'firebase/firestore';
import type { App as AdminApp, Auth as AdminAuth } from 'firebase-admin/app';
import type { Firestore as AdminFirestore } from 'firebase-admin/firestore';
import { firebaseConfig } from './config';

const isServer = typeof window === 'undefined';

// --- Client-side Firebase ---
let app: FirebaseApp;
let auth: Auth;
let db: Firestore;

function initializeClientServices() {
    if (getApps().length === 0) {
        app = initializeApp(firebaseConfig);
    } else {
        app = getApp();
    }
    auth = getAuth(app);
    db = getClientFirestore(app);
}

if (!isServer) {
    initializeClientServices();
}


// --- Server-side Firebase (Admin) ---
let adminApp: AdminApp;
let adminAuth: AdminAuth;
let adminDb: AdminFirestore;

async function initializeAdminServices() {
    const { initializeApp: initializeAdminApp, getApps: getAdminApps } = await import('firebase-admin/app');
    const { getAuth: getAdminAuth } = await import('firebase-admin/auth');
    const { getFirestore: getAdminFirestore } = await import('firebase-admin/firestore');
    
    if (getAdminApps().length === 0) {
        adminApp = initializeAdminApp({
            projectId: firebaseConfig.projectId,
        });
    } else {
        adminApp = getAdminApps()[0];
    }
    adminAuth = getAdminAuth(adminApp);
    adminDb = getAdminFirestore(adminApp);
}


// --- Exported Getters ---

export function getFirebaseApp(): FirebaseApp {
    if (isServer) {
        throw new Error("getFirebaseApp() is not available on the server. Use admin-specific functions instead.");
    }
    if (!app) initializeClientServices();
    return app;
}

export function getFirebaseAuth(): Auth {
    if (isServer) {
        throw new Error("getFirebaseAuth() is not available on the server. Use admin-specific functions instead.");
    }
    if (!auth) initializeClientServices();
    return auth;
}

// This function can be called from both client and server,
// but it will return different Firestore instances.
export async function getFirestoreDb(): Promise<Firestore | AdminFirestore> {
    if (isServer) {
        if (!adminDb) {
            await initializeAdminServices();
        }
        return adminDb;
    }
    
    if (!db) initializeClientServices();
    return db;
}
